sql:
SELECT COUNT(*) 
FROM diseases
WHERE date_added = '2023-01-01';

SELECT disease_id, disease_name, AVG(LENGTH(disease_name)) AS avg_length
FROM diseases
GROUP BY disease_id, disease_name;

SELECT disease_id, nutrient_id, COUNT(*) AS nutrient_association_count
FROM disease_nutrients
GROUP BY disease_id, nutrient_id;

SELECT patient_id, COUNT(*) AS engagement_count
FROM patient_engagement
GROUP BY patient_id;

SELECT precaution_name
FROM precautions
WHERE disease_id = 1;

SELECT DISTINCT first_name
FROM patients
WHERE patient_id IN (SELECT patient_id FROM patient_engagement);

external_knowledge:
- '2022 and 2023' refers to the time frame from January 1st, 2022, to December 31st, 2023; 
- 'on the platform' means added to the patients table between the specified dates; 
- 'how long it's been since they last engaged' is calculated in days and represents the average time elapsed since the last engagement; 
- 'ranked by those who have gone the longest without re-engaging' means the results are ordered from longest time since last engagement to shortest.
